text = open("/mnt/data/file-NZLBu8sY7TX9PwD6rQcs9k-text_to_analyse.txt","r",encoding="utf-8").read()

# Identify spans
# 1) First double-quoted ayah
quotes = []
idx = 0
while True:
    i = text.find('"', idx)
    if i == -1:
        break
    j = text.find('"', i+1)
    if j == -1:
        break
    quotes.append((i, j, text[i+1:j]))
    idx = j+1

# Based on manual classification: first quote Qur'an 49:13; second quote hadith
ayah1_span = {'start': quotes[0][0]+1, 'end': quotes[0][1], 'text': quotes[0][2]}
hadith_span = {'start': quotes[1][0]+1, 'end': quotes[1][1], 'text': quotes[1][2]}

# Parentheses segments
import re
open_ps = [m.start() for m in re.finditer(r'\(', text)]
segments = []
for i in open_ps:
    j = text.find(')', i+1)
    if j != -1:
        end = j
    else:
        nl = text.find('\n', i+1)
        end = nl if nl != -1 else len(text)
    segtext = text[i+1:end]
    segments.append((i, end, segtext))

ayah2_span = {'start': segments[0][0]+1, 'end': segments[0][1], 'text': segments[0][2]}
ayah3_span = {'start': segments[1][0]+1, 'end': segments[1][1], 'text': segments[1][2]}

ayah1_span, hadith_span, ayah2_span, ayah3_span

